use crossterm::event::{KeyCode, KeyModifiers};
use crate::{state::AppState, event::AppEvent};

pub fn handle(state: &mut AppState, event: AppEvent) {
    // Confirm dialog intercepts all keys
    if state.confirm_dialog.is_some() {
        match event {
            AppEvent::Key { code: KeyCode::Char('y'), .. } | AppEvent::Key { code: KeyCode::Char('Y'), .. } => {
                if let Some(dialog) = state.confirm_dialog.take() {
                    match dialog.action {
                        crate::state::ConfirmAction::DiscardFile { path } => {
                            let _ = clui_git::discard_file(&state.cwd, &path);
                            state.notifications.push(crate::state::NotificationEntry {
                                message: format!("Discarded {}", path),
                                kind: crate::state::NotificationKind::Info,
                                created_at: std::time::Instant::now(),
                                ttl_secs: 3,
                            });
                        }
                    }
                }
            }
            AppEvent::Key { code: KeyCode::Char('n'), .. }
            | AppEvent::Key { code: KeyCode::Char('N'), .. }
            | AppEvent::Key { code: KeyCode::Esc, .. } => {
                state.confirm_dialog = None;
            }
            _ => {}
        }
        return;
    }

    match event {
        AppEvent::Key { code: KeyCode::Char('q'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            state.should_quit = true;
        }
        AppEvent::Resize { cols, rows } => {
            state.layout.terminal_cols = cols;
            state.layout.terminal_rows = rows;
        }
        AppEvent::Tick => {
            state.notifications.retain(|n| !n.is_expired());
        }
        AppEvent::AgentChunk { tab_id, content } => {
            if let Some(tab) = state.tabs.iter_mut().find(|t| t.id == tab_id) {
                if tab.streaming.is_none() { tab.streaming = Some(String::new()); }
                tab.streaming.as_mut().unwrap().push_str(&content);
            }
        }
        AppEvent::AgentComplete { tab_id, content, tokens, cost } => {
            if let Some(tab) = state.tabs.iter_mut().find(|t| t.id == tab_id) {
                tab.streaming = None;
                tab.messages.push(crate::state::ChatMessage {
                    role: crate::state::MessageRole::Assistant,
                    content,
                });
                tab.status.context_tokens += tokens;
                tab.status.cost += cost;
            }
        }
        AppEvent::AgentError { tab_id: _, message } => {
            state.notifications.push(crate::state::NotificationEntry {
                message,
                kind: crate::state::NotificationKind::Error,
                created_at: std::time::Instant::now(),
                ttl_secs: 5,
            });
        }
        AppEvent::GitRefresh => {
            match clui_git::git_status(&state.cwd) {
                Ok(result) => {
                    state.git.branch = result.branch;
                    state.git.staged = result.staged.iter().map(|e| crate::state::GitFileEntry {
                        path: e.path.clone(),
                        status: e.status_char(),
                    }).collect();
                    state.git.unstaged = result.unstaged.iter().map(|e| crate::state::GitFileEntry {
                        path: e.path.clone(),
                        status: e.status_char(),
                    }).collect();
                    if let Some(tab) = state.active_tab_mut() {
                        tab.status.git_branch = state.git.branch.clone();
                    }
                }
                Err(_) => {}
            }
        }
        AppEvent::Key { code: KeyCode::Char('h'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            state.layout.left_visible = !state.layout.left_visible;
        }
        AppEvent::Key { code: KeyCode::Char('s'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            state.layout.right_visible = !state.layout.right_visible;
        }
        AppEvent::Key { code: KeyCode::Char('t'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            let id = (state.tabs.len() + 1).to_string();
            state.tabs.push(crate::state::TabState::new_chat(&id, "New Session"));
            state.active_tab = state.tabs.len() - 1;
        }
        AppEvent::Key { code: KeyCode::Char('w'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            if state.tabs.len() > 1 {
                state.tabs.remove(state.active_tab);
                if state.active_tab >= state.tabs.len() {
                    state.active_tab = state.tabs.len() - 1;
                }
            }
        }
        AppEvent::Key { code: KeyCode::Tab, .. } => {
            if !state.tabs.is_empty() {
                state.active_tab = (state.active_tab + 1) % state.tabs.len();
            }
        }
        AppEvent::Key { code: KeyCode::Char('1'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            if !state.tabs.is_empty() { state.active_tab = 0; }
        }
        AppEvent::Key { code: KeyCode::Char('2'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            if state.tabs.len() > 1 { state.active_tab = 1; }
        }
        AppEvent::Key { code: KeyCode::Char('3'), modifiers } if modifiers.contains(KeyModifiers::CONTROL) => {
            if state.tabs.len() > 2 { state.active_tab = 2; }
        }
        AppEvent::Key { code: KeyCode::Char('1'), modifiers } if modifiers.contains(KeyModifiers::ALT) => {
            state.layout.left_panel = crate::state::LeftPanel::Sessions;
        }
        AppEvent::Key { code: KeyCode::Char('2'), modifiers } if modifiers.contains(KeyModifiers::ALT) => {
            state.layout.left_panel = crate::state::LeftPanel::Git;
        }
        AppEvent::Key { code: KeyCode::Char('3'), modifiers } if modifiers.contains(KeyModifiers::ALT) => {
            state.layout.left_panel = crate::state::LeftPanel::Files;
        }
        AppEvent::Key { code: KeyCode::Char('8'), modifiers } if modifiers.contains(KeyModifiers::ALT) => {
            state.layout.right_panel = crate::state::RightPanel::Skills;
        }
        AppEvent::Key { code: KeyCode::Char('9'), modifiers } if modifiers.contains(KeyModifiers::ALT) => {
            state.layout.right_panel = crate::state::RightPanel::Mcps;
        }
        _ => {}
    }
}

use ratatui::Frame;
use crate::state::AppState;

pub fn render(f: &mut Frame, _state: &AppState) {
    let area = f.area();
    let block = ratatui::widgets::Block::default()
        .borders(ratatui::widgets::Borders::ALL)
        .border_type(ratatui::widgets::BorderType::Rounded)
        .title("clui");
    f.render_widget(block, area);
}

mod state;
mod event;
mod router;
mod agent_task;
mod ui;

use std::io;
use std::time::Duration;

use anyhow::Result;
use crossterm::{
    event::{self, Event, EnableMouseCapture, DisableMouseCapture},
    execute,
    terminal::{enable_raw_mode, disable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
};
use ratatui::{backend::CrosstermBackend, Terminal};

use event::AppEvent;
use state::AppState;

#[tokio::main]
async fn main() -> Result<()> {
    let cwd = std::env::current_dir()?;

    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
    let backend = CrosstermBackend::new(io::stdout());
    let mut terminal = Terminal::new(backend)?;
    terminal.clear()?;

    let size = terminal.size()?;
    let mut app = AppState::new(cwd);
    app.layout.terminal_cols = size.width;
    app.layout.terminal_rows = size.height;

    let result = run_loop(&mut terminal, &mut app).await;

    disable_raw_mode()?;
    execute!(io::stdout(), LeaveAlternateScreen, DisableMouseCapture)?;
    terminal.show_cursor()?;

    result
}

async fn run_loop(
    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
    state: &mut AppState,
) -> Result<()> {
    loop {
        terminal.draw(|f| ui::render(f, state))?;

        if event::poll(Duration::from_millis(16))? {
            match event::read()? {
                Event::Key(key) => {
                    router::handle(state, AppEvent::Key {
                        code: key.code,
                        modifiers: key.modifiers,
                    });
                }
                Event::Mouse(m) => {
                    router::handle(state, AppEvent::Mouse {
                        kind: m.kind,
                        col: m.column,
                        row: m.row,
                        modifiers: m.modifiers,
                    });
                }
                Event::Resize(cols, rows) => {
                    router::handle(state, AppEvent::Resize { cols, rows });
                }
                _ => {}
            }
        } else {
            router::handle(state, AppEvent::Tick);
        }

        if state.should_quit { break; }
    }
    Ok(())
}

